1	import { GoogleGenAI } from "@google/genai";
2	import { createAdminClient } from "@/lib/supabase";
3	import type { Artifact, Feedback, FeedbackSummary, FeedbackSummaryData, ServiceResult } from "@/types";
4	
5	const PROMPT_VERSION = "v1";
6	
7	function buildPrompt(artifact: Artifact, items: Feedback[]): string {
8	  const lines = items.map((f, i) => {
9	    const role = f.reviewer_role ? ` (${f.reviewer_role})` : "";
10	    return `${i + 1}. [${f.feedback_type}] ${f.reviewer_name}${role}: "${f.comment}"`;
11	  });
12	
13	  return `You are summarizing reviewer feedback for an AI-generated artifact.
14	
15	Artifact: "${artifact.title}"${artifact.description ? `\nDescription: "${artifact.description}"` : ""}
16	
17	Feedback (${items.length} item${items.length === 1 ? "" : "s"}):
18	${lines.join("\n")}
19	
20	Return a JSON object with exactly these fields:
21	- overall_assessment: 1-2 sentence summary of the overall reception
22	- open_issues: array of strings — one per unresolved issue (feedback_type=issue, status=open or needs_review)
23	- suggestions: array of strings — one per suggestion (feedback_type=suggestion)
24	- questions: array of strings — one per unanswered question (feedback_type=question)
25	- approval_count: integer count of approvals (feedback_type=approval)`;
26	}
27	
28	export function isValidSummaryData(data: unknown): data is FeedbackSummaryData {
29	  if (!data || typeof data !== "object") return false;
30	  const d = data as Record<string, unknown>;
31	  return (
32	    typeof d.overall_assessment === "string" &&
33	    Array.isArray(d.open_issues) &&
34	    (d.open_issues as unknown[]).every((x) => typeof x === "string") &&
35	    Array.isArray(d.suggestions) &&
36	    (d.suggestions as unknown[]).every((x) => typeof x === "string") &&
37	    Array.isArray(d.questions) &&
38	    (d.questions as unknown[]).every((x) => typeof x === "string") &&
39	    typeof d.approval_count === "number"
40	  );
41	}
42	
43	// Returns the cached summary without calling Gemini.
44	// Returns null only when no row exists (PGRST116); propagates real DB errors.
45	export async function getCachedSummary(artifactId: string): Promise<FeedbackSummary | null> {
46	  const supabase = createAdminClient();
47	  const { data, error } = await supabase
48	    .from("feedback_summaries")
49	    .select("*")
50	    .eq("artifact_id", artifactId)
51	    .single();
52	
53	  if (error) {
54	    if (error.code === "PGRST116") return null; // no row — expected
55	    throw new Error(`getCachedSummary DB error: ${error.message}`);
56	  }
57	  return data as FeedbackSummary;
58	}
59	
60	// Cache-first: returns cached if feedback_count unchanged and !forceRefresh.
61	// Calls Gemini and upserts when missing, stale, or forceRefresh=true.
62	export async function getSummary(
63	  artifactId: string,
64	  { forceRefresh = false }: { forceRefresh?: boolean } = {}
65	): Promise<ServiceResult<{ summary: FeedbackSummary; feedbackCount: number }>> {
66	  const supabase = createAdminClient();
67	
68	  const { data: artifact, error: artifactErr } = await supabase
69	    .from("artifacts")
70	    .select("*")
71	    .eq("id", artifactId)
72	    .single();
73	  if (artifactErr) {
74	    if (artifactErr.code === "PGRST116") return { ok: false, status: 404, message: "Artifact not found" };
75	    return { ok: false, status: 500, message: artifactErr.message };
76	  }
77	
78	  const { data: feedbackRows, error: feedbackErr } = await supabase
79	    .from("feedback")
80	    .select("*")
81	    .eq("artifact_id", artifactId)
82	    .order("created_at", { ascending: true });
83	  if (feedbackErr) return { ok: false, status: 500, message: feedbackErr.message };
84	
85	  const items = (feedbackRows ?? []) as Feedback[];
86	  const currentCount = items.length;
87	
88	  if (currentCount === 0) {
89	    return { ok: false, status: 422, message: "No feedback to summarize yet" };
90	  }
91	
92	  // Return cache if fresh
93	  const { data: cached } = await supabase
94	    .from("feedback_summaries")
95	    .select("*")
96	    .eq("artifact_id", artifactId)
97	    .single();
98	
99	  if (cached && cached.feedback_count === currentCount && !forceRefresh) {
100	    return { ok: true, data: { summary: cached as FeedbackSummary, feedbackCount: currentCount } };
101	  }
102	
103	  // Call Gemini
104	  const apiKey = process.env.GEMINI_API_KEY;
105	  if (!apiKey) return { ok: false, status: 500, message: "GEMINI_API_KEY not configured" };
106	
107	  const model = process.env.GEMINI_MODEL ?? "gemini-2.5-flash";
108	  const prompt = buildPrompt(artifact as Artifact, items);
109	
110	  let summaryData: FeedbackSummaryData;
111	  try {
112	    const ai = new GoogleGenAI({ apiKey });
113	    const response = await ai.models.generateContent({
114	      model,
115	      contents: prompt,
116	      config: { responseMimeType: "application/json" },
117	    });
118	
119	    const text = response.text;
120	    if (!text) {
121	      return { ok: false, status: 502, message: "Gemini returned an empty response" };
122	    }
123	
124	    let parsed: unknown;
125	    try {
126	      parsed = JSON.parse(text);
127	    } catch {
128	      return { ok: false, status: 502, message: "Gemini response was not valid JSON" };
129	    }
130	
131	    if (!isValidSummaryData(parsed)) {
132	      return {
133	        ok: false,
134	        status: 502,
135	        message: "Gemini response missing required fields (overall_assessment, open_issues, suggestions, questions, approval_count)",
136	      };
137	    }
138	
139	    summaryData = parsed;
140	  } catch (err) {
141	    return {
142	      ok: false,
143	      status: 502,
144	      message: `Gemini error: ${err instanceof Error ? err.message : String(err)}`,
145	    };
146	  }
147	
148	  // Upsert result
149	  const { data: upserted, error: upsertErr } = await supabase
150	    .from("feedback_summaries")
151	    .upsert(
152	      {
153	        artifact_id: artifactId,
154	        summary: summaryData,
155	        feedback_count: currentCount,
156	        model,
157	        prompt_version: PROMPT_VERSION,
158	        generated_at: new Date().toISOString(),
159	      },
160	      { onConflict: "artifact_id" }
161	    )
162	    .select("*")
163	    .single();
164	
165	  if (upsertErr) return { ok: false, status: 500, message: upsertErr.message };
166	  return { ok: true, data: { summary: upserted as FeedbackSummary, feedbackCount: currentCount } };
167	}
168

