1	import { createAdminClient } from "@/lib/supabase";
2	import { nanoid } from "nanoid";
3	import type { Artifact, ShareLink, CreateShareLinkBody, ServiceResult } from "@/types";
4	
5	// Exported for testing. The <= means a link expiring exactly now is already expired.
6	export function isShareLinkExpired(expiresAt: string): boolean {
7	  return new Date(expiresAt) <= new Date();
8	}
9	
10	export async function createShareLink(
11	  body: CreateShareLinkBody
12	): Promise<ServiceResult<ShareLink>> {
13	  const supabase = createAdminClient();
14	
15	  // Verify the artifact exists before inserting — avoids a raw FK constraint error
16	  const { error: artifactErr } = await supabase
17	    .from("artifacts")
18	    .select("id")
19	    .eq("id", body.artifact_id)
20	    .single();
21	  if (artifactErr) {
22	    if (artifactErr.code === "PGRST116") return { ok: false, status: 404, message: "Artifact not found" };
23	    return { ok: false, status: 500, message: artifactErr.message };
24	  }
25	
26	  const expiresInHours = body.expires_in_hours ?? 24 * 30;
27	  const expiresAt = new Date(Date.now() + expiresInHours * 60 * 60 * 1000).toISOString();
28	  const token = nanoid(21);
29	
30	  const { data, error } = await supabase
31	    .from("share_links")
32	    .insert({
33	      artifact_id: body.artifact_id,
34	      token,
35	      expires_at: expiresAt,
36	      label: body.label ?? null,
37	    })
38	    .select("*")
39	    .single();
40	
41	  if (error) return { ok: false, status: 500, message: error.message };
42	  return { ok: true, data: data as ShareLink };
43	}
44	
45	export async function validateShareLink(
46	  token: string
47	): Promise<ServiceResult<ShareLink & { artifact: Artifact }>> {
48	  const supabase = createAdminClient();
49	  const { data, error } = await supabase
50	    .from("share_links")
51	    .select("*, artifact:artifacts(*)")
52	    .eq("token", token)
53	    .single();
54	
55	  if (error) {
56	    if (error.code === "PGRST116") return { ok: false, status: 404, message: "Share link not found" };
